const body = $input.first().json.body;
const arquivos = body.arquivos || [];
const criterios = body.criterios || {};

return arquivos.map(arquivo => ({
  json: {
    filename: arquivo.filename,
    format: arquivo.format || 'bibtex',
    criterios: criterios
  },
  binary: {
    data: {
      data: Buffer.from(arquivo.content || '').toString('base64'),
      mimeType: 'text/plain',
      fileName: arquivo.filename
    }
  }
}));

function detectarFonte(text, filename) {
  if (text.includes('Scopus') && text.includes('EXPORT DATE')) return 'scopus';
  if (filename.toLowerCase().includes('scopus')) return 'scopus';
  if (filename.toLowerCase().includes('acm') ||
      text.includes('10.1145') ||
      text.includes('Association for Computing Machinery')) return 'acm';
  return 'ieee';
}

function parseBibTeX(text, fonte) {
  const entries = [];

  // Remove cabeçalho do Scopus
  const clean = text.replace(/^Scopus[\s\S]*?(?=@)/m, '').trim();

  // Normaliza line endings
  const normalized = clean.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // Divide entradas conforme o padrão da base
  let blocks;
  if (fonte === 'scopus' || fonte === 'acm') {
    blocks = normalized.split(/\n\n(?=@)/);
  } else {
    // IEEE: entradas coladas }@ sem quebra de linha
    blocks = normalized.split(/\}(?=@)/);
  }

  for (const block of blocks) {
    const trimmed = block.trim();
    if (!trimmed || !trimmed.startsWith('@')) continue;

    const headerMatch = trimmed.match(/^@(\w+)\s*\{\s*([^,\n]+),/);
    if (!headerMatch) continue;

    const entry = {
      _type: headerMatch[1].toLowerCase(),
      _key: headerMatch[2].trim()
    };

    // Extrai campos no formato campo={valor} com suporte a chaves aninhadas
    const fieldRegex = /^\s*(\w+)\s*=\s*\{((?:[^{}]|\{[^{}]*\})*)\}/gm;
    let fm;
    while ((fm = fieldRegex.exec(trimmed)) !== null) {
      const key = fm[1].toLowerCase().trim();
      const val = fm[2].replace(/\s+/g, ' ').trim();
      if (key && val) entry[key] = val;
    }

    // Fallback: campo = "valor" (aspas)
    const quotedRegex = /^\s*(\w+)\s*=\s*"([^"]*)"/gm;
    while ((fm = quotedRegex.exec(trimmed)) !== null) {
      const key = fm[1].toLowerCase().trim();
      if (!entry[key]) entry[key] = fm[2].replace(/\s+/g, ' ').trim();
    }

    // Normaliza campos de diferentes bases para nomes padrão
    entry.title    = entry.title    || entry.booktitle   || '';
    entry.author   = entry.author   || entry.authors     || '';
    entry.abstract = entry.abstract || entry.description || '';
    entry.journal  = entry.journal  || entry.abbrev_source_title || '';

    if (entry.title) entries.push(entry);
  }
  return entries;
}

function parseRIS(text) {
  const entries = [];
  const blocks = text.split(/ER\s*-\s*/).filter(b => b.trim());
  for (const block of blocks) {
    const entry = { _type: 'article', _key: '' };
    const lines = block.split(/\r?\n/);
    for (const line of lines) {
      const match = line.match(/^([A-Z][A-Z0-9])\s+-\s+(.+)$/);
      if (!match) continue;
      const [, tag, value] = match;
      switch (tag) {
        case 'TY': entry._type    = value.trim().toLowerCase(); break;
        case 'ID': entry._key     = value.trim(); break;
        case 'TI':
        case 'T1': entry.title    = value.trim(); break;
        case 'AU':
        case 'A1': entry.author   = entry.author
                     ? entry.author + '; ' + value.trim()
                     : value.trim(); break;
        case 'PY':
        case 'Y1': entry.year     = value.trim().split('/')[0]; break;
        case 'DO': entry.doi      = value.trim(); break;
        case 'AB':
        case 'N2': entry.abstract = value.trim(); break;
        case 'JO':
        case 'JF':
        case 'T2': entry.journal  = value.trim(); break;
      }
    }
    if (entry.title) entries.push(entry);
  }
  return entries;
}

const allItems = $input.all();
const results = [];

for (const inputItem of allItems) {
  let content = '';
  let filename = '';

  if (inputItem.binary && inputItem.binary.data) {
    content = Buffer.from(inputItem.binary.data.data, 'base64').toString('utf-8');
    filename = inputItem.binary.data.fileName || inputItem.json.filename || 'arquivo';
  }

  if (!content) continue;

  const isRIS = filename.toLowerCase().endsWith('.ris');
  let parsed;

  if (isRIS) {
    parsed = parseRIS(content);
  } else {
    const fonte = detectarFonte(content, filename);
    parsed = parseBibTeX(content, fonte);
  }

  for (const entry of parsed) {
    results.push({ json: { ...entry, _filename: filename, _format: isRIS ? 'ris' : 'bibtex' } });
  }
}

if (results.length === 0) {
  results.push({ json: { erro: 'nenhum artigo encontrado', _filename: '', _format: '' } });
}

return results;

function cleanText(text) {
  if (!text) return '';
  return text
    .replace(/<[^>]*>/g, '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function detectSource(filename) {
  if (!filename) return 'desconhecida';
  const f = filename.toLowerCase();
  if (f.includes('acm'))    return 'ACM';
  if (f.includes('ieee'))   return 'IEEE';
  if (f.includes('scopus')) return 'Scopus';
  return filename;
}

const item = $input.item.json;

return {
  titulo:  cleanText(item.titulo  || item.title   || item.Título || ''),
  autores: cleanText(item.autor   || item.author  || item.Autor  || ''),
  ano:     cleanText(item.ano     || item.year    || item.Ano    || ''),
  doi:     cleanText(item.doi     || item.DOI     || ''),
  resumo:  cleanText(item.resumo  || item.abstract|| item.Resumo || ''),
  fonte:   detectSource(item._filename),
};

function normalizarDecisao(decisao) {
  if (!decisao) return 'REVISAR';
  const d = decisao.toUpperCase();
  if (d.includes('INCLU')) return 'INCLUIR';
  if (d.includes('EXCLU')) return 'EXCLUIR';
  return 'REVISAR';
}

const limpeza = $('Limpeza').item.json;
const item = $input.item.json;
const output = item.output || '';

// Prefixo de espaço para evitar interpretação como fórmula no Sheets
const s = (v) => String(v || '').replace(/^[=+\-@]/, " $&");

// Extrai ano numérico do campo ano
const anoStr = String(limpeza.ano || '');
const anoMatch = anoStr.match(/\b(19|20)\d{2}\b/);
const anoNum = anoMatch ? parseInt(anoMatch[0]) : null;

// Exclusão automática por data — não depende do LLM
if (anoNum && (anoNum < 2019 || anoNum > 2025)) {
  return {
    titulo:        s(limpeza.titulo),
    autores:       s(limpeza.autores),
    ano:           s(limpeza.ano),
    doi:           s(limpeza.doi),
    fonte:         s(limpeza.fonte),
    decisao:       'EXCLUIR',
    confianca:     99,
    justificativa: `Excluído automaticamente: ano de publicação (${anoNum}) fora do intervalo definido nos critérios (2019-2025).`
  };
}

// Parseia resposta do agente
let triagem = {};
try {
  const jsonMatch = output.match(/\{[\s\S]*?\}(?=\s*$)/);
  triagem = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch(e) {
  triagem = {
    decisao: 'REVISAR',
    confianca: 0,
    justificativa: 'Erro ao parsear resposta da IA'
  };
}

// Corrige confiança 0 em exclusões por data que passaram pelo agente
const decisaoFinal = normalizarDecisao(triagem.decisao);
let confiancaFinal = Number(triagem.confianca) || 0;

if (decisaoFinal === 'EXCLUIR' &&
    triagem.justificativa &&
    triagem.justificativa.toLowerCase().includes('publicado em')) {
  confiancaFinal = 95;
}

return {
  titulo:        s(limpeza.titulo),
  autores:       s(limpeza.autores),
  ano:           s(limpeza.ano),
  doi:           s(limpeza.doi),
  fonte:         s(limpeza.fonte),
  decisao:       decisaoFinal,
  confianca:     confiancaFinal,
  justificativa: s(triagem.justificativa || ''),
};
